import{c as a,Q as e,j as r,m as i}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"How do I start a migration?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/start-migration.md","filePath":"guide/recipes/admin/start-migration.md","lastUpdated":1778912818000}'),o={name:"guide/recipes/admin/start-migration.md"};function n(s,t,l,c,d,g){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="how-do-i-start-a-migration" tabindex="-1">How do I start a migration? <a class="header-anchor" href="#how-do-i-start-a-migration" aria-label="Permalink to &quot;How do I start a migration?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong>, <strong>Infra Ops</strong>, or <strong>QA Admin</strong> (within scope)</p></div><p>Migrations move tenant data between instances or apply structural changes. The Migrations page kicks one off, and the job drawer tracks per-tenant progress live.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Migrations</strong> in the sidebar.</li><li>Click <strong>New Migration</strong>.</li><li>Pick the <strong>type</strong>: <ul><li><strong>Instance Replace</strong> — move tenants from one instance to another.</li><li><strong>Tenant Copy</strong> — duplicate a tenant to a new instance for testing.</li><li><strong>Schema Migration</strong> — apply a structural change to selected tenants.</li></ul></li><li>Fill in the type-specific fields. For instance-replace: source instance, target instance, tenants to move.</li><li>Choose <strong>Dry run</strong> if you want to validate without making changes.</li><li>Click <strong>Run</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The job appears in the list with status <strong>Queued</strong>, then <strong>Running</strong>. Click the row to open the job drawer — it shows per-tenant progress, phase logs (preflight, clone, import), and artifacts produced.</p><p>If the job is a dry-run, no live data is touched; the artifacts let you preview what would happen.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./rerun-migration">How do I rerun a failed migration?</a></li><li><a href="./rollback-migration">How do I roll back a migration?</a></li></ul>',10)])])}const u=a(o,[["render",n]]);export{h as __pageData,u as default};
